        //gr_gridView.SetColumn('cntrNo');
        ds_outGrid.setCellData(scwin.pre_RowPosition, 'cntrNo', scwin.pre_cntrNo);
        gr_gridView.setFocusedCell(0, 0);
        //gr_gridView.ColumnProp("cntrNo", "Edit") = "Upper";
