//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
  let ret1 = await $c.gus.cfValidate($p, [gr_gridView]);
  if (!ret1) {
    return;
  }
  if (ds_outGrid.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, "변경된 사항이 없습니다.");
    return;
  } else {
    let modifiedData = ds_outGrid.getModifiedJSON();
    ds_outGrid2.setJSON(modifiedData);
    ds_outGrid2.modifyAllStatus("U");
    let confirm = await $c.win.confirm($p, "저장하시겠습니까?");
    if (confirm) {
      $c.sbm.execute($p, sbm_save);
    }
  }
};

//-------------------------------------------------------------------------
// 처리취소
//-------------------------------------------------------------------------
scwin.btn_Cancel_onclick = async function (e) {
  var gridChkYn = false;
  for (var i = 0; i < ds_outGrid.getRowCount(); i++) {
    if (ds_outGrid.getCellData(i, 'gridChkBox') == 1) gridChkYn = true;
  }
  if (!gridChkYn) {
    $c.gus.cfAlertMsg($p, "선택된 사항이 없습니다.");
    return;
  }
  let ret1 = await $c.gus.cfValidate($p, [gr_gridView]);
  if (!ret1) {
    return;
  }
  if (ds_outGrid.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, "선택된 사항이 없습니다.");
  } else {
    let confirm = await $c.win.confirm($p, "반입(반출) 처리 취소 하시겠습니까?");
    if (confirm) {
      $c.sbm.execute($p, sbm_cancel);
    }
  }
};

