scwin.gr_gridView_oneditend = async function (rowIndex, columnIndex, value) {
  let colId = gr_gridView.getColumnID(columnIndex);
  if (colId == "chassisNo") {
    const oldData = ds_outGrid.getOriginalCellData(rowIndex, 'chassisNo');
    if (value === "") {
      return true;
    } else if (value === oldData) {
      return true;
    } else {
      scwin.pre_RowPosition = rowIndex;
      scwin.pre_chassisNo = value;
      scwin.pre_chassisEqCd = ds_outGrid.getCellData(scwin.pre_RowPosition, 'chassisEqCd');
      await scwin.f_chassisSearch('T', value);
    }
  } else if (colId == "vehclNo") {
    //차량번호
    const oldData = ds_outGrid.getOriginalCellData(rowIndex, 'vehclNo');
    if (value === "") {
      return true;
    } else if (value === oldData) {
      return true;
    } else {
      scwin.pre_RowPosition = rowIndex;
      await scwin.f_vehclSearch(true, 'T', value);
    }
  }
};
scwin.gr_gridView_onrowindexchange = function (rowIndex, oldRow) {
  const selfClsCd = ds_outGrid.getCellData(rowIndex, "selfClsCd");
  const wrkStpCd = ds_outGrid.getCellData(rowIndex, "wrkStpCd");
  const crryinoutClsCd = ds_outGrid.getCellData(rowIndex, "crryinoutClsCd");
  const indvdlAlloccarYn = ds_outGrid.getCellData(rowIndex, "indvdlAlloccarYn");
  const odrKndCd = ds_outGrid.getCellData(rowIndex, "odrKndCd");
  const cntrNoYn = ds_outGrid.getCellData(rowIndex, "cntrNoYn");
  const isSpecialCase = selfClsCd !== "JE" && wrkStpCd !== "0001" && crryinoutClsCd === "O" && indvdlAlloccarYn === "0" && odrKndCd === "C2";
  if (cntrNoYn === "0" && crryinoutClsCd === "O" || isSpecialCase) {
    gr_gridView.setCellReadOnly(rowIndex, "cntrNo", false);
  } else {
    gr_gridView.setCellReadOnly(rowIndex, "cntrNo", true);
  }
  if (selfClsCd === "JE") {
    // 자가반출인 경우 수정 불가
    gr_gridView.setCellReadOnly(rowIndex, "vehclNo", true);
    gr_gridView.setCellReadOnly(rowIndex, "chassisNo", true);
  } else {
    gr_gridView.setCellReadOnly(rowIndex, "vehclNo", false);
    gr_gridView.setCellReadOnly(rowIndex, "chassisNo", false);
  }
};
scwin.gr_gridView_onviewchange = function (info) {
  console.log(info);
  const row = info.rowIndex;
  const colid = info.colId;
  const newValue = info.newValue;
  const oldValue = info.oldValue;
  if (colid == "crryinoutDthh") {
    if (newValue === "") return;
    if (newValue.length !== 12) {
      $c.gus.cfAlertMsg($p, "반출입일시는 12자리 입니다.");
      ds_outGrid.setCellData(row, colid, ""); // 데이터 초기화
      gr_gridView.setFocusedCell(row, "gateoutDth"); // 다른 컬럼으로 포커스 이동 (기존 로직 유지)
      return;
    }

    // 3. 시/분 체크 (HHmm: 8번째 인덱스부터 끝까지)
    var timePart = newValue.substr(8, 4);
    if (!dscommon.cf_gidHourCheck(timePart)) {
      $c.gus.cfAlertMsg($p, "시분을 확인하십시요.");
      ds_outGrid.setCellData(row, colid, oldValue); // 이전 값으로 복구
      gr_gridView.setFocusedCell(row, colid); // 포커스 유지
      return;
    }

    // 4. 월 체크 (MM: 4번째 인덱스부터 2자리)
    var monthPart = parseInt(newValue.substr(4, 2), 10);
    if (monthPart < 1 || monthPart > 12) {
      $c.gus.cfAlertMsg($p, "월을 확인하십시요." + newValue.substr(4, 2));
      ds_outGrid.setCellData(row, colid, oldValue);
      gr_gridView.setFocusedCell(row, colid);
      return;
    }

    // 5. 일자 체크 (DD: 6번째 인덱스부터 2자리)
    var yearPart = newValue.substr(0, 4);
    var dayPart = parseInt(newValue.substr(6, 2), 10);
    var lastDay = dscommon.cf_lastDate(yearPart, newValue.substr(4, 2)); // 해당 월의 마지막 날짜 구하기

    if (dayPart < 1 || dayPart > lastDay) {
      $c.gus.cfAlertMsg($p, "일자를 확인하십시요." + newValue.substr(6, 2));
      ds_outGrid.setCellData(row, colid, oldValue);
      gr_gridView.setFocusedCell(row, colid);
      return;
    }
  }
};
